HYPOTHESIS_000002_AUTOGLUON_001_PY_BAA8C98AA6_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\ndef add_redshift_regime_catalog_consistency(raw, deps, aux):\n    redshift = raw["redshift"]\n\n    abs_redshift = redshift.abs()\n    signed_log_redshift = np.sign(redshift) * np.log1p(abs_redshift)\n    negative_redshift_flag = (redshift < 0).astype("uint8")\n\n    redshift_regime = pd.Series(\n        pd.Categorical(\n            np.select(\n                [\n                    abs_redshift < 0.003,      # near_zero\n                    abs_redshift < 0.08,       # low (includes 0.003 exactly)\n                    abs_redshift < 0.8,        # mid (includes 0.08 exactly)\n                    abs_redshift >= 0.8,       # high (includes 0.8 exactly)\n                ],\n                [\n                    "near_zero",\n                    "low",\n                    "mid",\n                    "high",\n                ],\n                default="high",\n            ),\n            categories=["near_zero", "low", "mid", "high"],\n            ordered=False,\n        ),\n        index=raw.index,\n    )\n\n    spectral_cross = raw["spectral_type"].astype("string") + " x " + redshift_regime.astype("string")\n    population_cross = raw["galaxy_population"].astype("string") + " x " + redshift_regime.astype("string")\n\n    new_features = pd.DataFrame(\n        {\n            "abs_redshift": abs_redshift,\n            "signed_log_redshift": signed_log_redshift,\n            "negative_redshift_flag": negative_redshift_flag,\n            "redshift_regime": redshift_regime,\n            "spectral_type_x_redshift_regime": pd.Categorical(spectral_cross),\n            "galaxy_population_x_redshift_regime": pd.Categorical(population_cross),\n        },\n        index=raw.index,\n    )\n    return new_features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "redshift_regime_catalog_consistency",\n        "fn": add_redshift_regime_catalog_consistency,\n        "depends_on": [],\n        "description": "Build redshift regime bins and cross them with spectral_type and galaxy_population.",\n    }\n]'

HYPOTHESIS_000003_AUTOGLUON_002_PY_1DE6FF1BE7_SOURCE = 'import numpy as np\nimport pandas as pd\n\ndef add_galactic_sightline_context(raw, deps, aux):\n    alpha_rad = np.deg2rad((pd.to_numeric(raw["alpha"], errors="coerce") % 360.0).to_numpy(dtype=float))\n    delta_rad = np.deg2rad(pd.to_numeric(raw["delta"], errors="coerce").to_numpy(dtype=float))\n\n    # Equatorial unit-sphere coordinates (wrap-safe via alpha modulo 360)\n    cos_delta = np.cos(delta_rad)\n    x_eq = cos_delta * np.cos(alpha_rad)\n    y_eq = cos_delta * np.sin(alpha_rad)\n    z_eq = np.sin(delta_rad)\n\n    # J2000 equatorial -> Galactic rotation matrix\n    x_gal = (\n        -0.0548755604 * x_eq\n        + -0.8734370902 * y_eq\n        + -0.4838350155 * z_eq\n    )\n    y_gal = (\n        0.4941094279 * x_eq\n        + -0.4448296300 * y_eq\n        + 0.7469822445 * z_eq\n    )\n    z_gal = (\n        -0.8676661490 * x_eq\n        + -0.1980763734 * y_eq\n        + 0.4559837762 * z_eq\n    )\n\n    z_clip = np.clip(z_gal, -1.0, 1.0)\n    b_rad = np.arcsin(z_clip)\n    b_deg = np.degrees(b_rad)\n    abs_b_deg = np.abs(b_deg)\n\n    l_rad = np.arctan2(y_gal, x_gal)\n    l_deg = np.degrees(l_rad) % 360.0\n    l_rad = np.deg2rad(l_deg)\n\n    sin_l = np.sin(l_rad)\n    cos_l = np.cos(l_rad)\n    sin_b = np.sin(b_rad)\n    cos_b = np.cos(b_rad)\n\n    dist_to_galactic_center = np.degrees(np.arccos(np.clip(x_gal, -1.0, 1.0)))\n    dist_to_galactic_anticenter = np.degrees(np.arccos(np.clip(-x_gal, -1.0, 1.0)))\n    dist_to_north_galactic_pole = np.degrees(np.arccos(np.clip(z_gal, -1.0, 1.0)))\n    dist_to_south_galactic_pole = np.degrees(np.arccos(np.clip(-z_gal, -1.0, 1.0)))\n\n    b_band_edges = (0.0, 10.0, 20.0, 35.0, 50.0, 70.0, 90.0000001)\n    b_band_labels = ("0-10", "10-20", "20-35", "35-50", "50-70", "70-90")\n    b_band = pd.cut(\n        abs_b_deg,\n        bins=b_band_edges,\n        labels=b_band_labels,\n        right=False,\n        include_lowest=True,\n    )\n\n    l_sector_edges = tuple(np.arange(0.0, 390.0, 30.0))\n    l_sector_labels = tuple(f"{int(start):03d}-{int(start + 30):03d}" for start in l_sector_edges[:-1])\n    l_sector = pd.cut(\n        l_deg,\n        bins=l_sector_edges,\n        labels=l_sector_labels,\n        right=False,\n        include_lowest=True,\n    )\n\n    b_band_str = b_band.astype(str)\n    l_sector_str = l_sector.astype(str)\n    crossed_regime = b_band_str + "|" + l_sector_str\n\n    return pd.DataFrame(\n        {\n            "eq_x": x_eq,\n            "eq_y": y_eq,\n            "eq_z": z_eq,\n            "gal_l_deg": l_deg,\n            "gal_b_deg": b_deg,\n            "gal_abs_b_deg": abs_b_deg,\n            "gal_sin_l": sin_l,\n            "gal_cos_l": cos_l,\n            "gal_sin_b": sin_b,\n            "gal_cos_b": cos_b,\n            "gal_plane_angular_distance_deg": abs_b_deg,\n            "gal_dist_to_galactic_center_deg": dist_to_galactic_center,\n            "gal_dist_to_galactic_anticenter_deg": dist_to_galactic_anticenter,\n            "gal_dist_to_north_pole_deg": dist_to_north_galactic_pole,\n            "gal_dist_to_south_pole_deg": dist_to_south_galactic_pole,\n            "gal_b_band": b_band_str,\n            "gal_l_sector": l_sector_str,\n            "gal_b_band_l_sector": crossed_regime,\n        },\n        index=raw.index,\n    )\n\nFEATURE_GROUPS = [\n    {\n        "name": "galactic_sightline_context",\n        "fn": add_galactic_sightline_context,\n        "depends_on": [],\n        "description": "Create Galactic coordinate-derived spatial features including smooth angular encodings, center/pole distances, and coarse latitude-longitude regime bins.",\n    }\n]'

HYPOTHESIS_000011_AUTOGLUON_001_PY_32FA31194A_SOURCE = 'import pandas as pd\nimport numpy as np\n\n_LRG_MARGIN_CLIP_BOUNDS = (-20.0, 20.0)\n\n\ndef add_lrg_target_cut_margins(raw, deps, aux):\n    g_minus_r = raw["g"] - raw["r"]\n    r_minus_i = raw["r"] - raw["i"]\n\n    c_perp = r_minus_i - (g_minus_r / 4.0) - 0.177\n    c_parallel = 0.7 * g_minus_r + 1.2 * (r_minus_i - 0.177)\n\n    cut_i_cperp_margin = c_perp.abs() - 0.2\n    cut_i_r_mag_margin = raw["r"] - 19.2\n    cut_i_r_cpar_margin = raw["r"] - (13.116 + c_parallel / 0.3)\n\n    cut_ii_cperp_margin = (0.449 - g_minus_r / 6.0) - c_perp\n    cut_ii_gmri_margin = (1.296 + 0.25 * r_minus_i) - g_minus_r\n    cut_ii_r_mag_margin = raw["r"] - 19.5\n\n    cut_i_score = np.maximum.reduce(\n        [\n            cut_i_cperp_margin.to_numpy(),\n            cut_i_r_mag_margin.to_numpy(),\n            cut_i_r_cpar_margin.to_numpy(),\n        ]\n    )\n    cut_ii_score = np.maximum.reduce(\n        [\n            cut_ii_cperp_margin.to_numpy(),\n            cut_ii_gmri_margin.to_numpy(),\n            cut_ii_r_mag_margin.to_numpy(),\n        ]\n    )\n\n    new_features = pd.DataFrame(\n        {\n            "lrg_g_minus_r": g_minus_r,\n            "lrg_r_minus_i": r_minus_i,\n            "lrg_c_perp": c_perp,\n            "lrg_c_parallel": c_parallel,\n            "lrg_cut_i_margin_c_perp": cut_i_cperp_margin,\n            "lrg_cut_i_margin_r_mag": cut_i_r_mag_margin,\n            "lrg_cut_i_margin_r_parallel_surface": cut_i_r_cpar_margin,\n            "lrg_cut_i_max_signed_violation": pd.Series(\n                cut_i_score, index=raw.index, dtype="float64"\n            ),\n            "lrg_cut_ii_margin_c_perp": cut_ii_cperp_margin,\n            "lrg_cut_ii_margin_color": cut_ii_gmri_margin,\n            "lrg_cut_ii_margin_r_mag": cut_ii_r_mag_margin,\n            "lrg_cut_ii_max_signed_violation": pd.Series(\n                cut_ii_score, index=raw.index, dtype="float64"\n            ),\n        },\n        index=raw.index,\n    )\n\n    lower, upper = _LRG_MARGIN_CLIP_BOUNDS\n    for col in (\n        "lrg_cut_i_margin_c_perp",\n        "lrg_cut_i_margin_r_mag",\n        "lrg_cut_i_margin_r_parallel_surface",\n        "lrg_cut_i_max_signed_violation",\n        "lrg_cut_ii_margin_c_perp",\n        "lrg_cut_ii_margin_color",\n        "lrg_cut_ii_margin_r_mag",\n        "lrg_cut_ii_max_signed_violation",\n    ):\n        new_features[col] = new_features[col].clip(lower=lower, upper=upper)\n\n    return new_features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "lrg_target_cut_margins",\n        "fn": add_lrg_target_cut_margins,\n        "depends_on": [],\n        "description": "Computes SDSS DR2/LRG Cut I and Cut II g-r/r-i rotated-color margins and compact max-violation scores for each photometric target selection family.",\n    }\n]'

HYPOTHESIS_000015_AUTOGLUON_002_PY_8B5EAD10F8_SOURCE = 'import numpy as np\nimport pandas as pd\n\n\ndef add_redshift_template_domain_margins(raw, deps, aux):\n    redshift = pd.to_numeric(raw["redshift"], errors="coerce")\n    index = redshift.index\n    z = redshift.to_numpy(dtype=float)\n    finite = np.isfinite(z)\n\n    velocity_width = 1200.0 / 299792.458\n    galaxy_low, galaxy_high = -0.01, 1.0\n    qso_low, qso_high = 0.0333, 7.0\n    regime_boundaries = (0.0, 0.0333, 1.0, 2.2, 3.0, 3.5, 4.5, 5.0)\n    regime_names = ("0_0", "0_0333", "1_0", "2_2", "3_0", "3_5", "4_5", "5_0")\n\n    features = pd.DataFrame(index=index)\n\n    abs_z = np.abs(z)\n    features["redshift_abs"] = abs_z\n    features["redshift_sign"] = np.sign(z)\n\n    stellar_margin = np.where(\n        finite,\n        np.where(abs_z > velocity_width, abs_z - velocity_width, 0.0),\n        np.nan,\n    )\n    features["redshift_stellar_velocity_margin"] = stellar_margin\n\n    features["redshift_stellar_velocity_signed_margin"] = np.where(\n        finite,\n        np.where(\n            abs_z > velocity_width,\n            (abs_z - velocity_width) * np.sign(z),\n            0.0,\n        ),\n        np.nan,\n    )\n    redshift_in_stellar_velocity_domain = np.zeros(len(z), dtype=np.bool_)\n    redshift_in_stellar_velocity_domain[finite] = abs_z[finite] <= velocity_width\n    features["redshift_in_stellar_velocity_domain"] = redshift_in_stellar_velocity_domain\n\n    galaxy_lower_margin = np.where(finite, z - galaxy_low, np.nan)\n    galaxy_upper_margin = np.where(finite, z - galaxy_high, np.nan)\n    galaxy_in_domain = finite & (z >= galaxy_low) & (z <= galaxy_high)\n    galaxy_distance = np.where(\n        finite,\n        np.where(\n            galaxy_in_domain,\n            0.0,\n            np.where(\n                z < galaxy_low,\n                galaxy_low - z,\n                z - galaxy_high,\n            ),\n        ),\n        np.nan,\n    )\n    features["redshift_galaxy_lower_margin"] = galaxy_lower_margin\n    features["redshift_galaxy_upper_margin"] = galaxy_upper_margin\n    features["redshift_in_galaxy_domain"] = galaxy_in_domain.astype(np.bool_)\n    features["redshift_galaxy_distance_to_domain"] = galaxy_distance\n\n    qso_lower_margin = np.where(finite, z - qso_low, np.nan)\n    qso_upper_margin = np.where(finite, z - qso_high, np.nan)\n    qso_in_domain = finite & (z >= qso_low) & (z <= qso_high)\n    qso_distance = np.where(\n        finite,\n        np.where(\n            qso_in_domain,\n            0.0,\n            np.where(\n                z < qso_low,\n                qso_low - z,\n                z - qso_high,\n            ),\n        ),\n        np.nan,\n    )\n    features["redshift_qso_lower_margin"] = qso_lower_margin\n    features["redshift_qso_upper_margin"] = qso_upper_margin\n    features["redshift_in_qso_domain"] = qso_in_domain.astype(np.bool_)\n    features["redshift_qso_distance_to_domain"] = qso_distance\n\n    regime_bin = np.full(z.shape[0], -1, dtype=np.int16)\n    finite_vals = z[finite]\n    if finite_vals.size > 0:\n        regime_bin[finite] = np.searchsorted(\n            np.array(regime_boundaries, dtype=float),\n            finite_vals,\n            side="right",\n        )\n    features["redshift_regime_bin"] = regime_bin\n\n    for boundary, name in zip(regime_boundaries, regime_names):\n        safe_label = name.replace(".", "p")\n        features[f"redshift_minus_bnd_{safe_label}"] = np.where(finite, z - boundary, np.nan)\n        in_or_equal_boundary = np.zeros(len(z), dtype=np.bool_)\n        in_or_equal_boundary[finite] = z[finite] >= boundary\n        features[f"redshift_ge_bnd_{safe_label}"] = in_or_equal_boundary\n\n    return features\n\n\nFEATURE_GROUPS = [\n    {\n        "name": "redshift_template_domain_margins",\n        "fn": add_redshift_template_domain_margins,\n        "depends_on": [],\n        "description": "Builds redshift-domain geometry features for stellar, galaxy, and quasar template feasibility with signed margins, in-domain flags, and ordered boundary regime indicators.",\n    },\n]'

